const input = $input.first().json;
const action = input.action || 'list_entities';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.home-assistant&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;

if (!creds.ha_url) return [{ json: { error: 'Home Assistant URL not configured. Use add_credential to set ha_url (e.g. https://abc.ui.nabu.casa).' } }];
if (!creds.ha_token) return [{ json: { error: 'Home Assistant access token not configured. Use add_credential to set ha_token (Long-Lived Access Token from HA -> Profile -> Security).' } }];

const baseUrl = creds.ha_url.replace(/\/+$/, '').replace(/\/api$/, '');
const apiBase = baseUrl + '/api';
const haHeaders = {
  'Authorization': 'Bearer ' + creds.ha_token,
  'Content-Type': 'application/json'
};

function formatEntity(e) {
  const tags = e.attributes || {};
  let line = e.entity_id + ' = ' + e.state;
  if (tags.friendly_name && tags.friendly_name !== e.entity_id) line += ' (' + tags.friendly_name + ')';
  if (tags.unit_of_measurement) line += ' ' + tags.unit_of_measurement;
  return line;
}

// === list_entities ===
if (action === 'list_entities') {
  try {
    const states = await helpers.httpRequest({ method: 'GET', url: apiBase + '/states', headers: haHeaders });
    const domain = input.domain ? String(input.domain).toLowerCase() : null;
    const search = input.search ? String(input.search).toLowerCase() : null;
    const limit = parseInt(input.limit) || 50;

    let filtered = states;
    if (domain) filtered = filtered.filter(e => e.entity_id.startsWith(domain + '.'));
    if (search) filtered = filtered.filter(e => {
      const fn = (e.attributes && e.attributes.friendly_name) || '';
      return e.entity_id.toLowerCase().includes(search) || fn.toLowerCase().includes(search);
    });

    if (filtered.length === 0) {
      const domList = [...new Set(states.map(e => e.entity_id.split('.')[0]))].sort().join(', ');
      return [{ json: { result: 'No entities found.' + (domain ? ' Available domains: ' + domList : '') } }];
    }

    let out;
    if (!domain && !search) {
      const byDomain = {};
      for (const e of filtered) {
        const d = e.entity_id.split('.')[0];
        byDomain[d] = (byDomain[d] || 0) + 1;
      }
      out = 'Total entities: ' + filtered.length + '\n\nBy domain:\n';
      for (const d of Object.keys(byDomain).sort()) out += '  ' + d + ': ' + byDomain[d] + '\n';
      out += '\nUse domain parameter (e.g. light, switch, sensor) or search parameter to list specific entities.';
    } else {
      out = filtered.length + ' entities' + (domain ? ' (' + domain + ')' : '') + ':\n\n';
      for (const e of filtered.slice(0, limit)) out += formatEntity(e) + '\n';
      if (filtered.length > limit) out += '\n... and ' + (filtered.length - limit) + ' more (increase limit to see all)';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (e) {
    return [{ json: { error: 'Failed to list entities: ' + (e.message || String(e)) } }];
  }
}

// === get_state ===
if (action === 'get_state') {
  const entityId = input.entity_id;
  if (!entityId) return [{ json: { error: 'Parameter "entity_id" is required (e.g. light.kitchen, sensor.temperature).' } }];
  try {
    const e = await helpers.httpRequest({ method: 'GET', url: apiBase + '/states/' + encodeURIComponent(entityId), headers: haHeaders });
    const tags = e.attributes || {};
    let out = e.entity_id + '\n';
    out += 'State: ' + e.state;
    if (tags.unit_of_measurement) out += ' ' + tags.unit_of_measurement;
    out += '\n';
    if (tags.friendly_name) out += 'Name: ' + tags.friendly_name + '\n';
    if (e.last_changed) out += 'Last changed: ' + e.last_changed + '\n';
    const skip = new Set(['friendly_name', 'unit_of_measurement', 'supported_features', 'attribution']);
    const attrs = Object.keys(tags).filter(k => !skip.has(k));
    if (attrs.length) {
      out += '\nAttributes:\n';
      for (const k of attrs.slice(0, 20)) {
        let v = tags[k];
        if (Array.isArray(v)) v = v.length > 5 ? v.slice(0, 5).join(', ') + ' ...' : v.join(', ');
        else if (typeof v === 'object' && v !== null) v = JSON.stringify(v).substring(0, 100);
        out += '  ' + k + ': ' + v + '\n';
      }
    }
    return [{ json: { result: out } }];
  } catch (e) {
    if ((e.message || '').includes('404')) return [{ json: { error: 'Entity not found: ' + entityId } }];
    return [{ json: { error: 'Failed to get state: ' + (e.message || String(e)) } }];
  }
}

// === list_services ===
if (action === 'list_services') {
  try {
    const services = await helpers.httpRequest({ method: 'GET', url: apiBase + '/services', headers: haHeaders });
    const domain = input.domain ? String(input.domain).toLowerCase() : null;
    let filtered = domain ? services.filter(d => d.domain === domain) : services;
    if (filtered.length === 0) {
      return [{ json: { result: 'No services found' + (domain ? ' for domain "' + domain + '"' : '') + '. Available domains: ' + services.map(d => d.domain).join(', ') } }];
    }
    let out;
    if (!domain) {
      out = filtered.length + ' service domains available:\n\n';
      for (const d of filtered) {
        const svcNames = Object.keys(d.services || {}).slice(0, 10);
        out += d.domain + ': ' + svcNames.join(', ') + (Object.keys(d.services).length > 10 ? ' ...' : '') + '\n';
      }
    } else {
      const d = filtered[0];
      out = 'Services in domain "' + d.domain + '":\n\n';
      for (const [svc, info] of Object.entries(d.services || {})) {
        out += '- ' + d.domain + '.' + svc;
        if (info.description) out += ' - ' + info.description;
        out += '\n';
        if (info.fields) {
          const fields = Object.keys(info.fields);
          if (fields.length) out += '    fields: ' + fields.join(', ') + '\n';
        }
      }
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (e) {
    return [{ json: { error: 'Failed to list services: ' + (e.message || String(e)) } }];
  }
}

// === call_service ===
if (action === 'call_service') {
  const domain = input.domain;
  const service = input.service;
  if (!domain || !service) return [{ json: { error: 'Parameters "domain" and "service" are required (e.g. domain=light, service=turn_on).' } }];

  const body = {};
  if (input.entity_id) body.entity_id = String(input.entity_id);

  if (input.service_data) {
    try {
      const extra = typeof input.service_data === 'string' ? JSON.parse(input.service_data) : input.service_data;
      Object.assign(body, extra);
    } catch (e) {
      return [{ json: { error: 'Invalid service_data JSON: ' + e.message + '. Must be valid JSON like {"brightness": 128}.' } }];
    }
  }

  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: apiBase + '/services/' + encodeURIComponent(domain) + '/' + encodeURIComponent(service),
      headers: haHeaders,
      body: JSON.stringify(body)
    });
    const changed = Array.isArray(resp) ? resp.length : 0;
    let out = 'Service ' + domain + '.' + service + ' called successfully.';
    if (input.entity_id) out += ' Target: ' + input.entity_id;
    if (changed > 0) {
      out += '\nChanged ' + changed + ' entit' + (changed === 1 ? 'y' : 'ies') + ':';
      for (const e of resp.slice(0, 10)) out += '\n  ' + formatEntity(e);
    }
    return [{ json: { result: out } }];
  } catch (e) {
    const msg = e.message || String(e);
    if (msg.includes('400')) return [{ json: { error: 'Bad request (400). Check domain/service name and parameters. Use list_services to see valid services.' } }];
    if (msg.includes('404')) return [{ json: { error: 'Service not found: ' + domain + '.' + service } }];
    return [{ json: { error: 'Failed to call service: ' + msg } }];
  }
}

// === speak ===
if (action === 'speak') {
  const message = input.message;
  if (!message) return [{ json: { error: 'Parameter "message" is required (the text to speak).' } }];
  const hint = input.device_hint ? String(input.device_hint).toLowerCase() : null;

  try {
    const states = await helpers.httpRequest({ method: 'GET', url: apiBase + '/states', headers: haHeaders });

    // 1. Prefer assist_satellite (best path for HA Voice devices — bypasses media_player routing)
    const satellites = states.filter(e => e.entity_id.startsWith('assist_satellite.') && e.state !== 'unavailable');
    if (satellites.length > 0) {
      let target = null;
      if (hint) {
        target = satellites.find(e => {
          const fn = ((e.attributes && e.attributes.friendly_name) || '').toLowerCase();
          return e.entity_id.toLowerCase().includes(hint) || fn.includes(hint);
        });
      }
      if (!target) target = satellites[0];

      try {
        await helpers.httpRequest({
          method: 'POST',
          url: apiBase + '/services/assist_satellite/announce',
          headers: haHeaders,
          body: JSON.stringify({ entity_id: target.entity_id, message: String(message) })
        });
        const fn = (target.attributes && target.attributes.friendly_name) || target.entity_id;
        return [{ json: { result: 'Spoken via assist_satellite on "' + fn + '" (' + target.entity_id + ')\nMessage: ' + message } }];
      } catch (e) {
        // Fall through to media_player fallback if announce fails
      }
    }

    // 2. Fallback: tts.speak via media_player
    const mediaPlayers = states.filter(e => e.entity_id.startsWith('media_player.') && e.state !== 'unavailable');
    if (mediaPlayers.length === 0) {
      return [{ json: { error: 'No speakable devices found. Need an assist_satellite or an available media_player. ' + (satellites.length > 0 ? 'assist_satellite.announce call failed and no media_player fallback available.' : '') } }];
    }

    let player = null;
    if (hint) {
      player = mediaPlayers.find(e => {
        const fn = ((e.attributes && e.attributes.friendly_name) || '').toLowerCase();
        return e.entity_id.toLowerCase().includes(hint) || fn.includes(hint);
      });
    }
    if (!player) player = mediaPlayers[0];

    const ttsEngines = states.filter(e => e.entity_id.startsWith('tts.'));
    if (ttsEngines.length === 0) {
      return [{ json: { error: 'No TTS engine configured in Home Assistant. Add a TTS integration (Cloud, Google, Piper) or use assist_satellite.announce directly via call_service.' } }];
    }
    const ttsEntity = ttsEngines[0].entity_id;

    await helpers.httpRequest({
      method: 'POST',
      url: apiBase + '/services/tts/speak',
      headers: haHeaders,
      body: JSON.stringify({
        entity_id: ttsEntity,
        media_player_entity_id: player.entity_id,
        message: String(message)
      })
    });
    const pfn = (player.attributes && player.attributes.friendly_name) || player.entity_id;
    return [{ json: { result: 'Spoken via tts.speak on "' + pfn + '" (' + player.entity_id + ', engine: ' + ttsEntity + ')\nMessage: ' + message } }];
  } catch (e) {
    return [{ json: { error: 'Failed to speak: ' + (e.message || String(e)) } }];
  }
}

return [{ json: { error: 'Unknown action: ' + action + '. Available: list_entities, get_state, list_services, call_service, speak.' } }];
